import{ab as e,G as o,H as i,E as n,U as a,N as t,ad as p,X as c}from"./framework-756f1659.js";const l={},r=p(`<h2 id="什么是spring-boot-它主要有哪些优点" tabindex="-1"><a class="header-anchor" href="#什么是spring-boot-它主要有哪些优点" aria-hidden="true">#</a> 什么是spring boot，它主要有哪些优点</h2><p>Springboot是spring的子项目，称为一站式解决方案，集成了外部很多的优秀的框架，如常用的mysql、jdbc。</p><p>主要优点：通过maven导入各种jar包，可以减少jar包的冲突；屏息了繁琐的xml配置文件；集成的开发框架，可以做到开箱即用。</p><h2 id="为什么要用spring-boot" tabindex="-1"><a class="header-anchor" href="#为什么要用spring-boot" aria-hidden="true">#</a> 为什么要用spring boot？</h2><p><strong>优点</strong>：</p><p>快速创建独立运行的Spring应用以及与主流框架集成</p><p>1.1. 使用嵌入式的Servlet容器，应用最终可以打成Jar包的形式独立运行。</p><p>1.2. 版本仲裁中心和不同的场景启动器(starter)为Spring Boot应用开发管理这不同的框架和版本依赖。</p><p>1.3. 约定大于配置，Spring Boot为开发者导入项目所使用的框架设置好了默认配置。</p><p>1.4. Java Config代替了原有难以管理的SpringXML配置。</p><p>1.5. 提供了准生产环境的运行时的应用监控。</p><p>1.6. 与云计算的天然集成，Spring Cloud相关框架技术。</p><p><strong>缺点</strong>：</p><p>从以上优点可知，Spring Boot的最大优点就是为开发者屏蔽了底层框架的复杂性。这样恰好是其缺点。Spring Boot降低了入门门槛，但是其封装使后期学习曲线陡峭。所以如果需要熟练的掌握该框架，必须了解其底层原理。</p><h2 id="spring-boot跟spring-cloud的区别" tabindex="-1"><a class="header-anchor" href="#spring-boot跟spring-cloud的区别" aria-hidden="true">#</a> spring boot跟spring cloud的区别？</h2><p>SpringBoot只是一个快速开发框架，使用注解简化了xml配置，内置了Servlet容器，以Java应用程序进行执行。</p><p>SpringCloud是一系列框架的集合，可以包含SpringBoot。</p><h2 id="spring-boot与spring-mvc的区别" tabindex="-1"><a class="header-anchor" href="#spring-boot与spring-mvc的区别" aria-hidden="true">#</a> Spring Boot与Spring MVC的区别</h2><ol><li>Spring Boot是Spring和Spring MVC的整合，而Spring MVC只是Spring的一个模块，一个轻量级的Web层框架</li><li>Spring Boot几乎可以实现零配置，所有功能使用注解进行开发，运用了&#39;约定大于配置&#39;的思想，简化了项目开发难度，而Spring MVC需要依赖于xml配置进行开发</li><li>Spring Boot提供了内置的tomcat,可以打成jar包直接运行，也可以使用外置容器</li><li>Spring Boot还集成了许多第三方库配置，例如JDBC, Mongo, Redis等,应用这些第三方库，几乎可以零配置使用</li></ol><h2 id="springboot如何修改端口号" tabindex="-1"><a class="header-anchor" href="#springboot如何修改端口号" aria-hidden="true">#</a> SpringBoot如何修改端口号？</h2><p>:::: tabs cache-lifetime=&quot;5&quot; :options=&quot;{ useUrlFragment: false }&quot;</p><p>::: tab yml</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token key atrule">server</span><span class="token punctuation">:</span>
    <span class="token key atrule">port</span><span class="token punctuation">:</span> <span class="token number">8888</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>:::</p><p>::: tab properties</p><div class="language-properties line-numbers-mode" data-ext="properties"><pre class="language-properties"><code><span class="token key attr-name">server.port</span> <span class="token punctuation">=</span> <span class="token value attr-value">8888</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>:::</p><p>::: tab 命令行</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">java</span> <span class="token parameter variable">-jar</span> demo.jar <span class="token parameter variable">--server.port</span><span class="token operator">=</span><span class="token number">8888</span>
<span class="token function">java</span> - <span class="token assign-left variable">Dserver.port</span><span class="token operator">=</span><span class="token number">8888</span> <span class="token parameter variable">-jar</span> demo.jar
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>:::</p><p>::::</p><h2 id="springboot热部署的方式" tabindex="-1"><a class="header-anchor" href="#springboot热部署的方式" aria-hidden="true">#</a> Springboot热部署的方式</h2><p>SpringBoot 1.3后才拥有SpringBoot devtools热部署</p><h3 id="方式一-spring-boot-devtools" tabindex="-1"><a class="header-anchor" href="#方式一-spring-boot-devtools" aria-hidden="true">#</a> 方式一：spring-boot-devtools</h3><p>在项目的pom文件中添加依赖:</p><div class="language-xml line-numbers-mode" data-ext="xml"><pre class="language-xml"><code><span class="token comment">&lt;!--热部署jar--&gt;</span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>dependency</span><span class="token punctuation">&gt;</span></span>
	<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>groupId</span><span class="token punctuation">&gt;</span></span>org.springframework.boot<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>groupId</span><span class="token punctuation">&gt;</span></span>
	<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>artifactId</span><span class="token punctuation">&gt;</span></span>spring-boot-devtools<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>artifactId</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>dependency</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>然后在Settings→Build→Compiler中将<code>Build project automatically</code>勾选上，最后使用 shift+ctrl+alt+&quot;/&quot; （IDEA中的快捷键） 选择&quot;<code>Registry</code>&quot; 然后勾选 <code>compiler.automake.allow.when.app.running</code></p><p>还需要修改配置：</p><div class="language-properties line-numbers-mode" data-ext="properties"><pre class="language-properties"><code><span class="token key attr-name">spring</span><span class="token punctuation">:</span>
<span class="token key attr-name">  devtools</span><span class="token punctuation">:</span>
<span class="token key attr-name">    restart</span><span class="token punctuation">:</span>
<span class="token key attr-name">      enabled</span><span class="token punctuation">:</span> <span class="token value attr-value">true  #设置开启热部署</span>
<span class="token key attr-name">      additional-paths</span><span class="token punctuation">:</span> <span class="token value attr-value">src/main/java #重启目录</span>
<span class="token key attr-name">      exclude</span><span class="token punctuation">:</span> <span class="token value attr-value">WEB-INF/**</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container note"><p class="hint-container-title">原理</p><p>devtools实现原理是使用了两个classloader，一个是<code>base classloader</code>，用来加载那些不会改变的类（比如第三方jar包等），另一个ClassLoader加载会更改的类，称为<code>restart ClassLoader</code>，这样在有代码更改的时候，原来的restart ClassLoader会被丢弃，重新创建一个ClassLoader，也就意味着应用程序重新启动通常比“冷启动”快得多，因为<code>base classloader</code>已经填充好了并且是可用的。</p><p>简而言之就是：<strong>通过监控类路径资源，当类路径上的文件发生更改时，自动重新启动应用程序，由于只需要重新读取被修改的类，所以要比冷启动快</strong>。</p></div><h3 id="方式二-spring-loaded" tabindex="-1"><a class="header-anchor" href="#方式二-spring-loaded" aria-hidden="true">#</a> 方式二：Spring Loaded</h3><p>在项目中添加如下代码</p><div class="language-xml line-numbers-mode" data-ext="xml"><pre class="language-xml"><code> <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>build</span><span class="token punctuation">&gt;</span></span>
 <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>plugins</span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>plugin</span><span class="token punctuation">&gt;</span></span>
  <span class="token comment">&lt;!-- springBoot编译插件--&gt;</span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>groupId</span><span class="token punctuation">&gt;</span></span>org.springframework.boot<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>groupId</span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>artifactId</span><span class="token punctuation">&gt;</span></span>spring-boot-maven-plugin<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>artifactId</span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>dependencies</span><span class="token punctuation">&gt;</span></span>
   <span class="token comment">&lt;!-- spring热部署 --&gt;</span>
   <span class="token comment">&lt;!-- 该依赖在此处下载不下来，可以放置在build标签外部下载完成后再粘贴进plugin中 --&gt;</span>
   <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>dependency</span><span class="token punctuation">&gt;</span></span>
   <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>groupId</span><span class="token punctuation">&gt;</span></span>org.springframework<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>groupId</span><span class="token punctuation">&gt;</span></span>
   <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>artifactId</span><span class="token punctuation">&gt;</span></span>springloaded<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>artifactId</span><span class="token punctuation">&gt;</span></span>
   <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>version</span><span class="token punctuation">&gt;</span></span>1.2.6.RELEASE<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>version</span><span class="token punctuation">&gt;</span></span>
   <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>dependency</span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>dependencies</span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>plugin</span><span class="token punctuation">&gt;</span></span>
 <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>plugins</span><span class="token punctuation">&gt;</span></span>
 <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>build</span><span class="token punctuation">&gt;</span></span> 
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>添加完毕后需要使用mvn指令运行：</p><p>首先找到IDEA中的<code>Edit configurations</code>，然后进行如下操作：（点击左上角的&quot;+&quot;,然后选择maven将出现右侧面板，在红色划线部位输入如图所示指令，你可以为该指令命名(此处命名为<code>MvnSpringBootRun</code>）</p><p>点击保存将会在IDEA项目运行部位出现，点击绿色箭头运行即可。</p><h3 id="方式三-jrebel" tabindex="-1"><a class="header-anchor" href="#方式三-jrebel" aria-hidden="true">#</a> 方式三：Jrebel</h3>`,47),u={href:"https://www.iocoder.cn/Fight/IDEA-JRebel-plug-in-hot-deployment/",target:"_blank",rel:"noopener noreferrer"},d=p(`<h2 id="spring-boot-中如何解决跨域问题" tabindex="-1"><a class="header-anchor" href="#spring-boot-中如何解决跨域问题" aria-hidden="true">#</a> Spring Boot 中如何解决跨域问题 ?</h2><p>跨域可以在前端通过 JSONP 来解决，但是 JSONP 只可以发送 GET 请求，无法发送其他类型的请求，在 RESTful 风格的应用中，就显得非常鸡肋。</p><p>因此我们推荐在后端通过 （CORS，Crossorigin resource sharing） 来解决跨域问题。这种解决方案并非 Spring Boot 特有的，在传统的SSM 框架中，就可以通过 CORS 来解决跨域问题，只不过之前我们是在 XML 文件中配置 CORS ，现在可以通过实现<code>WebMvcConfifigurer</code>接口然后重写<code>addCorsMappings</code>方法解决跨域问题。</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token annotation punctuation">@Configuration</span>
<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">CorsConfig</span> <span class="token keyword">implements</span> <span class="token class-name">WebMvcConfigurer</span> <span class="token punctuation">{</span>
	<span class="token annotation punctuation">@Override</span>
	<span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">addCorsMappings</span><span class="token punctuation">(</span><span class="token class-name">CorsRegistry</span> registry<span class="token punctuation">)</span> <span class="token punctuation">{</span>
		registry<span class="token punctuation">.</span><span class="token function">addMapping</span><span class="token punctuation">(</span><span class="token string">&quot;/**&quot;</span><span class="token punctuation">)</span>
		<span class="token punctuation">.</span><span class="token function">allowedOrigins</span><span class="token punctuation">(</span><span class="token string">&quot;*&quot;</span><span class="token punctuation">)</span>
		<span class="token punctuation">.</span><span class="token function">allowCredentials</span><span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span>
		<span class="token punctuation">.</span><span class="token function">allowedMethods</span><span class="token punctuation">(</span><span class="token string">&quot;GET&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;POST&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;PUT&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;DELETE&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;OPTIONS&quot;</span><span class="token punctuation">)</span>
		<span class="token punctuation">.</span><span class="token function">maxAge</span><span class="token punctuation">(</span><span class="token number">3600</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
	<span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>也可以在方法或者类上加<code>@CrossOrigin</code>注解来解决：</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token annotation punctuation">@RestController</span>
<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">DeliveryController</span> <span class="token punctuation">{</span>
	<span class="token annotation punctuation">@CrossOrigin</span>
    <span class="token annotation punctuation">@PostMapping</span><span class="token punctuation">(</span><span class="token string">&quot;/delivery/addRecord&quot;</span><span class="token punctuation">)</span>
    <span class="token keyword">public</span> <span class="token class-name">CommonResult</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Integer</span><span class="token punctuation">&gt;</span></span> <span class="token function">add</span><span class="token punctuation">(</span><span class="token annotation punctuation">@RequestBody</span> <span class="token class-name">DeliveryRecord</span> deliveryRecord<span class="token punctuation">)</span> <span class="token punctuation">{</span>
       <span class="token comment">// ...</span>
    <span class="token punctuation">}</span>
    
    <span class="token annotation punctuation">@GetMapping</span><span class="token punctuation">(</span><span class="token string">&quot;/delivery/checkRecord&quot;</span><span class="token punctuation">)</span>
    <span class="token keyword">public</span> <span class="token class-name">CommonResult</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">DeliveryRecord</span><span class="token punctuation">&gt;</span></span> <span class="token function">checkRecord</span><span class="token punctuation">(</span><span class="token annotation punctuation">@RequestParam</span> <span class="token class-name">Integer</span> deliveryId<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token comment">// ...</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="highlight-lines"><br><br><br><div class="highlight-line"> </div><br><br><br><br><br><br><br><br><br></div><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,6),k={href:"https://blog.csdn.net/munangs/article/details/123252149",target:"_blank",rel:"noopener noreferrer"},g=p('<h2 id="spring-boot的自动配置是如何实现的" tabindex="-1"><a class="header-anchor" href="#spring-boot的自动配置是如何实现的" aria-hidden="true">#</a> Spring boot的自动配置是如何实现的？</h2><blockquote><p><code>@SpringBootApplication</code>=<code>@Configuration</code> + <code>@EnableAutoConfiguration</code> + <code>@ComponentScan</code></p></blockquote><p>其实说白了SpringBoot的自动配置，实际是依赖<code>@Conditional来</code>实现的。</p><p><code>@Conditional</code>是一个条件注解，是Spring4提供的一个新特性，用于根据特定条件来控制Bean的创建行为。</p><p>SpringBoot中对@Conditional的引用链如下：</p><p>@SpringBootApplication -&gt; @EnableAutoConfiguration -&gt; @Import(AutoConfigurationImportSelector.class) -&gt; 在<code>AutoConfigurationImportSelector</code>类中会执行<code>getCandidateConfigurations（AnnotationMetadata metadata, AnnotationAttributes attributes）</code>方法，里面有一行：</p><p><code>List configurations = SpringFactoriesLoader.loadFactoryNames( getSpringFactoriesLoaderFactoryClass(), getBeanClassLoader());</code></p><p>这里就会扫描具有MEAT-INF/spring.factories文件的jar包，得到所有的配置类。</p><p>而这些配置类上，基本都有以下类型的注解：</p><p>@ConditionalOnClass, @ConditionalOnMissingClass</p><p>@ConditionalOnBean, @ConditionalOnMissingBean</p><p>@ConditionalOnProperty, @ConditionalOnResource</p><p>@ConditionalOnEnabledHealthIndicator, ...</p><p>如果满足条件，则把对应的配置类装载入spring容器。</p><p>总结一下，其实就是 Spring Boot 在启动的时候，按照约定去读取 Spring Boot Starter 的配置信息，再根据配置信息对资源进行初始化，并注入到 Spring 容器中。这样 Spring Boot 启动完毕后，就已经准备好了一切资源，使用过程中直接注入对应 Bean 资源即可。</p><p><strong>参考：</strong></p>',16),v={href:"https://blog.csdn.net/Let_me_tell_you/article/details/80951595",target:"_blank",rel:"noopener noreferrer"},m={href:"https://mp.weixin.qq.com/s/gs2zLSH6m9ijO0-pP2sr9Q",target:"_blank",rel:"noopener noreferrer"},b=p(`<h2 id="conditional相关的注解" tabindex="-1"><a class="header-anchor" href="#conditional相关的注解" aria-hidden="true">#</a> @Conditional相关的注解？</h2><p>@Conditional要配合Condition的实现类（ClassCondition）进行使用。SpringBoot 提供的常用条件注解：</p><ol><li><p>@ConditionalOnBean 组合@Conditional注解，当容器中有指定Bean才开启配置。</p></li><li><p>@ConditionalOnMissingBean 组合@Conditional注解，当容器中没有值当Bean才可开启配置。</p></li><li><p>@ConditionalOnClass 组合@Conditional注解，当容器中有指定Class才可开启配置。</p></li><li><p>@ConditionalOnMissingClass 组合@Conditional注解，当容器中没有指定Class才可开启配置。</p></li><li><p>@ConditionOnWebApplication 组合@Conditional注解，当前项目类型是WEB项目才可开启配置。项目有以下三种类型：</p><pre><code> 	1. ANY：任意一个Web项目

 	1. SERVLET： Servlet的Web项目

 	1. REACTIVE ：基于reactive-base的Web项目
</code></pre></li><li><p>@ConditionOnNotWebApplication 组合@Conditional注解，当前项目类型不是WEB项目才可开启配置。</p></li><li><p>@ConditionalOnProperty 组合@Conditional注解，当指定的属性有指定的值时才可开启配置。</p></li><li><p>@ConditionalOnExpression 组合@Conditional注解，当SpEl表达式为true时才可开启配置。</p></li><li><p>@ConditionOnJava 组合@Conditional注解，当运行的Java JVM在指定的版本范围时才开启配置。</p></li><li><p>@ConditionalResource 组合@Conditional注解，当类路径下有指定的资源才开启配置。</p></li><li><p>@ConditionOnJndi 组合@Conditional注解，当指定的JNDI存在时才开启配置。</p></li><li><p>@ConditionalOnCloudPlatform 组合@Conditional注解，当指定的云平台激活时才可开启配置。</p></li><li><p>@ConditiomalOnSingleCandidate 组合@Conditional注解，当制定的Class在容器中只有一个Bean，或者同时有多个但为首选时才开启配置。</p></li></ol><h2 id="springboot-中怎么禁用某些自动配置特性" tabindex="-1"><a class="header-anchor" href="#springboot-中怎么禁用某些自动配置特性" aria-hidden="true">#</a> SpringBoot 中怎么禁用某些自动配置特性？</h2><p>有 3 种方法。如果我们想禁用某些自动配置特性，可以使用 <code>@EnableAutoConfiguration</code> 或 <code>@SpringBootApplication</code> 注解的 <code>exclude</code> 属性来指明。</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token comment">// 方案1，下面的代码段是使 DataSourceAutoConfiguration 无效：</span>
<span class="token annotation punctuation">@EnableAutoConfiguration</span><span class="token punctuation">(</span>exclude <span class="token operator">=</span> <span class="token class-name">DataSourceAutoConfiguration</span><span class="token punctuation">.</span><span class="token keyword">class</span><span class="token punctuation">)</span>
<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">MyConfiguration</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>
<span class="token comment">// 方案2</span>
<span class="token annotation punctuation">@SpringBootApplication</span><span class="token punctuation">(</span>exclude <span class="token operator">=</span> <span class="token class-name">DataSourceAutoConfiguration</span><span class="token punctuation">.</span><span class="token keyword">class</span><span class="token punctuation">)</span>
<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">MyConfiguration</span> <span class="token punctuation">{</span> <span class="token punctuation">}</span>
<span class="token comment">// 方案3，在配置文件中配置</span>
spring<span class="token punctuation">.</span>autoconfigure<span class="token punctuation">.</span>exclude<span class="token operator">=</span><span class="token class-name"><span class="token namespace">org<span class="token punctuation">.</span>springframework<span class="token punctuation">.</span>boot<span class="token punctuation">.</span>autoconfigure<span class="token punctuation">.</span>jdbc<span class="token punctuation">.</span></span>DataSourceAutoConfiguration</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="springboot的加载流程" tabindex="-1"><a class="header-anchor" href="#springboot的加载流程" aria-hidden="true">#</a> SpringBoot的加载流程？</h2>`,7),h={href:"https://www.jianshu.com/p/dc12081b3598",target:"_blank",rel:"noopener noreferrer"},C=p(`<h2 id="springboot运行原理" tabindex="-1"><a class="header-anchor" href="#springboot运行原理" aria-hidden="true">#</a> SpringBoot运行原理</h2><p>1） 如果我们使用的是SpringApplication的静态run方法，那么，这个方法里面首先要创建一个SpringApplication对象实例，然后调用这个创建好的SpringApplication的实例方法。在SpringApplication实例初始化的时候，它会提前做几件事情：</p><ul><li>根据classpath里面是否存在某个特征类（org.springframework.web.context.ConfigurableWebApplicationContext）来决定是否应该创建一个为Web应用使用的ApplicationContext类型。</li><li>使用SpringFactoriesLoader在应用的classpath中查找并加载所有可用的ApplicationContextInitializer。</li><li>使用SpringFactoriesLoader在应用的classpath中查找并加载所有可用的ApplicationListener。</li><li>推断并设置main方法的定义类。</li></ul><p>2） SpringApplication实例初始化完成并且完成设置后，就开始执行run方法的逻辑了，方法执行伊始，首先遍历执行所有通过SpringFactoriesLoader可以查找到并加载的SpringApplicationRunListener。调用它们的started()方法，告诉这些SpringApplicationRunListener，“嘿，SpringBoot应用要开始执行咯！”。</p><p>3） 创建并配置当前Spring Boot应用将要使用的Environment（包括配置要使用的PropertySource以及Profile）。</p><p>4） 遍历调用所有SpringApplicationRunListener的environmentPrepared()的方法，告诉他们：“当前SpringBoot应用使用的Environment准备好了咯！”。</p><p>5） 如果SpringApplication的showBanner属性被设置为true，则打印banner。</p><p>6） 根据用户是否明确设置了applicationContextClass类型以及初始化阶段的推断结果，决定该为当前SpringBoot应用创建什么类型的ApplicationContext并创建完成，然后根据条件决定是否添加ShutdownHook，决定是否使用自定义的BeanNameGenerator，决定是否使用自定义的ResourceLoader，当然，最重要的，将之前准备好的Environment设置给创建好的ApplicationContext使用。</p><p>7） ApplicationContext创建好之后，SpringApplication会再次借助Spring-FactoriesLoader，查找并加载classpath中所有可用的ApplicationContext-Initializer，然后遍历调用这些ApplicationContextInitializer的initialize（applicationContext）方法来对已经创建好的ApplicationContext进行进一步的处理。</p><p>8） 遍历调用所有SpringApplicationRunListener的contextPrepared()方法。</p><p>9） 最核心的一步，将之前通过@EnableAutoConfiguration获取的所有配置以及其他形式的IoC容器配置加载到已经准备完毕的ApplicationContext。</p><p>10） 遍历调用所有SpringApplicationRunListener的contextLoaded()方法。</p><p>11） 调用ApplicationContext的refresh()方法，完成IoC容器可用的最后一道工序。</p><p>12） 查找当前ApplicationContext中是否注册有CommandLineRunner，如果有，则遍历执行它们。</p><p>13） 正常情况下，遍历执行SpringApplicationRunListener的finished()方法、（如果整个过程出现异常，则依然调用所有SpringApplicationRunListener的finished()方法，只不过这种情况下会将异常信息一并传入处理。</p><h2 id="spring-boot容器替换" tabindex="-1"><a class="header-anchor" href="#spring-boot容器替换" aria-hidden="true">#</a> Spring boot容器替换？</h2><div class="language-xml line-numbers-mode" data-ext="xml"><pre class="language-xml"><code><span class="token comment">&lt;!-- 下面的配置将使用undertow来做服务器而不是tomcat --&gt;</span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>dependency</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>groupId</span><span class="token punctuation">&gt;</span></span>org.springframework.boot<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>groupId</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>artifactId</span><span class="token punctuation">&gt;</span></span>spring-boot-starter-web<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>artifactId</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>exclusions</span><span class="token punctuation">&gt;</span></span>
        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>exclusion</span><span class="token punctuation">&gt;</span></span>
            <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>groupId</span><span class="token punctuation">&gt;</span></span>org.springframework.boot<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>groupId</span><span class="token punctuation">&gt;</span></span>
            <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>artifactId</span><span class="token punctuation">&gt;</span></span>spring-boot-starter-tomcat<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>artifactId</span><span class="token punctuation">&gt;</span></span>
        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>exclusion</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>exclusions</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>dependency</span><span class="token punctuation">&gt;</span></span>

<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>dependency</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>groupId</span><span class="token punctuation">&gt;</span></span>org.springframework.boot<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>groupId</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>artifactId</span><span class="token punctuation">&gt;</span></span>spring-boot-starter-undertow<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>artifactId</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>dependency</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在spring-boot-starter-web中，使用<code>&lt;exclusion&gt;</code>排除掉web中引入的tomcat，使用<code>&lt;dependency&gt;</code>重新导入undertow 即可。也可以用同样的方法，把容器替换为Jetty。</p><h2 id="spring-boot集成mybatis" tabindex="-1"><a class="header-anchor" href="#spring-boot集成mybatis" aria-hidden="true">#</a> Spring boot集成Mybatis?</h2><p>加入依赖即可。这个starter是mybatis提供的。</p><div class="language-xml line-numbers-mode" data-ext="xml"><pre class="language-xml"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>dependency</span><span class="token punctuation">&gt;</span></span>  
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>groupId</span><span class="token punctuation">&gt;</span></span>org.mybatis.spring.boot<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>groupId</span><span class="token punctuation">&gt;</span></span>  
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>artifactId</span><span class="token punctuation">&gt;</span></span>mybatis-spring-boot-starter<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>artifactId</span><span class="token punctuation">&gt;</span></span>  
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>version</span><span class="token punctuation">&gt;</span></span>1.3.0<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>version</span><span class="token punctuation">&gt;</span></span>  
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>dependency</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="springboot读取配置相关注解有" tabindex="-1"><a class="header-anchor" href="#springboot读取配置相关注解有" aria-hidden="true">#</a> SpringBoot读取配置相关注解有？</h2><ul><li>@PropertySource</li><li>@Value</li><li>@Environment</li><li>@ConfigurationProperties</li></ul><h2 id="starters是什么" tabindex="-1"><a class="header-anchor" href="#starters是什么" aria-hidden="true">#</a> Starters是什么？</h2><p>Starters可以理解为启动器，它包含了一系列可以集成到应用里面的依赖包，你可以一站式集成Spring及其他技术，而不需要到处找示例代码和依赖包。如你想使用<code>Spring JPA</code>访问数据库，只要加入<code>spring-boot-starter-data-jpa</code>启动器依赖就能使用了。</p><p>Starters包含了许多项目中需要用到的依赖，它们能快速持续的运行，都是一系列得到支持的管理传递性依赖。</p><p><strong>Starters命名</strong></p><p>Spring Boot官方的启动器都是以<code>spring-boot-starter-</code>开头命名的，代表了一个特定的应用类型。</p><p>第三方的启动器不能以spring-boot开头命名，它们都被Spring Boot官方保留。一般一个第三方的应该这样命名，像mybatis的<code>mybatis-spring-boot-starter</code>。</p><h2 id="spring-boot的starter的执行原理" tabindex="-1"><a class="header-anchor" href="#spring-boot的starter的执行原理" aria-hidden="true">#</a> spring boot的starter的执行原理</h2><p>利用starter实现自动化配置只需要两个条件――maven依赖、配置文件，这里简单介绍下starter实现自动化配置的流程。</p><p>引入maven实质上就是导入jar包，spring-boot启动的时候会找到starter jar包中的resources/META-INF/spring.factories文件，根据spring.factories文件中的配置，找到需要自动配置的类。</p><h2 id="spring-boot自己实现starter" tabindex="-1"><a class="header-anchor" href="#spring-boot自己实现starter" aria-hidden="true">#</a> Spring Boot自己实现starter?</h2>`,33),f={href:"https://www.cnblogs.com/hello-shf/p/10864977.html",target:"_blank",rel:"noopener noreferrer"},S=p(`<h2 id="spring-boot-starter-parent-有什么用" tabindex="-1"><a class="header-anchor" href="#spring-boot-starter-parent-有什么用" aria-hidden="true">#</a> Spring-boot-starter-parent 有什么用 ?</h2><p>我们都知道，新创建一个 Spring Boot 项目，默认都是有 parent 的，这个 parent 就是 spring-boot-starter-parent ，spring-boot-starter-parent 主要有如下作用：</p><p>定义了 Java 编译版本为 1.8 。</p><p>使用 UTF-8 格式编码。</p><p>继承自spring-boot-dependencies，这个里边定义了依赖的版本，也正是因为继承了这个依赖，所以我们在写依赖时才不需要写版本号。</p><p>执行打包操作的配置。</p><p>自动化的资源过滤。</p><p>自动化的插件配置。</p><p>针对 application.properties 和 application.yml 的资源过滤，包括通过 profile</p><p>定义的不同环境的配置文件，例如 application-dev.properties 和 application-dev.yml。</p><h2 id="spring-boot-打成的-jar-和普通的-jar-有什么区别" tabindex="-1"><a class="header-anchor" href="#spring-boot-打成的-jar-和普通的-jar-有什么区别" aria-hidden="true">#</a> Spring Boot 打成的 jar 和普通的 jar 有什么区别 ?</h2><p>Spring Boot 项目最终打包成的 jar 是可执行 jar ，这种 jar 可以直接通过 java -jar xxx.jar 命令来运行，这种 jar 不可以作为普通的 jar 被其他项目依赖，即使依赖了也无法使用其中的类。</p><p>Spring Boot 的 jar 无法被其他项目依赖，主要还是他和普通 jar 的结构不同。普通的 jar 包，解压后直接就是包名，包里就是我们的代码，而 Spring Boot 打包成的可执行 jar 解压后，在 \\BOOT-INF\\classes 目录下才是我们的代码，因此无法被直接引用。如果非要引用，可以在 pom.xml 文件中增加配置，将 Spring Boot 项目打包成两个 jar ，一个可执行，一个可引用。</p><h2 id="如何在-spring-boot-启动的时候运行一些特定的代码" tabindex="-1"><a class="header-anchor" href="#如何在-spring-boot-启动的时候运行一些特定的代码" aria-hidden="true">#</a> 如何在 Spring Boot 启动的时候运行一些特定的代码？</h2><p>可以实现接口 ApplicationRunner 或者 CommandLineRunner，这两个接口实现方式一样，它们都只提供了一个 run 方法。如下所示：</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">interface</span> <span class="token class-name">CommandLineRunner</span> <span class="token punctuation">{</span>   
	<span class="token doc-comment comment">/**

     * Callback used to run the bean.
     * <span class="token keyword">@param</span> <span class="token parameter">args</span> incoming main method arguments
     * <span class="token keyword">@throws</span> <span class="token reference"><span class="token class-name">Exception</span></span> on error
     */</span>
	<span class="token keyword">void</span> <span class="token function">run</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span> args<span class="token punctuation">)</span> <span class="token keyword">throws</span> <span class="token class-name">Exception</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
<span class="token comment">//---</span>
<span class="token keyword">public</span> <span class="token keyword">interface</span> <span class="token class-name">ApplicationRunner</span> <span class="token punctuation">{</span>
	<span class="token doc-comment comment">/**
     * Callback used to run the bean.
     * <span class="token keyword">@param</span> <span class="token parameter">args</span> incoming application arguments
     * <span class="token keyword">@throws</span> <span class="token reference"><span class="token class-name">Exception</span></span> on error
     */</span>
	<span class="token keyword">void</span> <span class="token function">run</span><span class="token punctuation">(</span><span class="token class-name">ApplicationArguments</span> args<span class="token punctuation">)</span> <span class="token keyword">throws</span> <span class="token class-name">Exception</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>使用方式</strong></p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">import</span> <span class="token namespace">org<span class="token punctuation">.</span>springframework<span class="token punctuation">.</span>boot<span class="token punctuation">.</span></span><span class="token operator">*</span>
<span class="token keyword">import</span> <span class="token namespace">org<span class="token punctuation">.</span>springframework<span class="token punctuation">.</span>stereotype<span class="token punctuation">.</span></span><span class="token operator">*</span>
<span class="token annotation punctuation">@Component</span>
<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">MyBean</span> <span class="token keyword">implements</span> <span class="token class-name">CommandLineRunner</span> <span class="token punctuation">{</span>
   <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">run</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span> args<span class="token punctuation">)</span> <span class="token punctuation">{</span>
       <span class="token comment">// Do something...</span>
   <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
<span class="token comment">// 或者</span>
<span class="token annotation punctuation">@Bean</span>
<span class="token keyword">public</span> <span class="token class-name">CommandLineRunner</span> <span class="token function">init</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
   <span class="token keyword">return</span> <span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span> strings<span class="token punctuation">)</span> <span class="token operator">-&gt;</span> <span class="token punctuation">{</span>
   <span class="token punctuation">}</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container note"><p class="hint-container-title">启动顺序</p><p>如果启动的时候有多个ApplicationRunner和CommandLineRunner，想控制它们的启动顺序，可以实现 <code>org.springframework.core.Ordered</code>接口或者使用 <code>org.springframework.core.annotation.Order</code>注解。</p></div>`,19);function x(y,w){const s=c("ExternalLinkIcon");return o(),i("div",null,[r,n("p",null,[a("Jrebel是一款热部署插件。可参考这篇文章来配置："),n("a",u,[a("IDEA JRebel 插件热部署（史上最全）"),t(s)])]),d,n("p",null,[a("参考："),n("a",k,[a("注解@CrossOrigin"),t(s)])]),g,n("p",null,[n("a",v,[a("CSDN - SpringBoot自动配置原理"),t(s)])]),n("p",null,[n("a",m,[a("Spring Boot自动配置原理、实战"),t(s)])]),b,n("p",null,[n("a",h,[a("https://www.jianshu.com/p/dc12081b3598"),t(s)])]),C,n("p",null,[n("a",f,[a("SpringBoot应用篇（一）：自定义starter"),t(s)])]),S])}const A=e(l,[["render",x],["__file","index.html.vue"]]);export{A as default};
